 接收机通信 # 从接收机获取数据 # 您拿到 service 后 (参考1.2)，可以通过 service 的 requestReceiverListener 方法来实现对接收机 数据的监听，requestReceiverListener 要求您传入 IReceiverListener.Stub 对象，您可以继承该对象， 实现相关接口，通过对接口的实现来获得需要的数据。其中有的回调接口是会按一定的频率回调 (比如位置信息和卫星信息)，有的接口是需要给接收机发命令 (参考3.2) 才会回调。章节1.5中已给 出相关获取坐标信息的示例，这里不再赘述，只对相关需要实现的接口给出代码和注释，具体如 下:
ReceiverListener mIReceiverListener = new IReceiverListener.Stub() { ​ /*** Handles CHC_MESSAGE_TYPE_GNSS *********************************************************/ ​ @Override public void getSatelliteConstellations(int i) throws RemoteException { // Number of constellations } ​ @Override public void getSatelliteUsedNums(SatelliteNumber satelliteNumber) throws RemoteException { // Number of satellites and number of usable satellites } ​ @Override public void getSatelliteInfos(SatelliteInfo[] satelliteInfos) throws RemoteException { // Detailed information about satellites (see SatelliteInfo class under 7GnssInfo for detailed structure) } ​ @Override public void getPositionEx(PositionInfo positionInfo, Course course) throws RemoteException { // Receiver position information output, PositionInfo class includes position, solution status, GPS time, accuracy, etc. } ​ @Override public void getBasePosition(Position position) throws RemoteException { // Base station coordinates output in RTK differential mode } ​ @Override public void getGnssDops(DopsInfo dopsInfo) throws RemoteException { // DOP values } ​ @Override public void getGpggaData(byte[] bytes) throws RemoteException { // GGA data } ​ @Override public void getBaseParams(BaseParams params, WorkWay way) throws RemoteException { // Get receiver base station parameters } ​ @Override public void getIoEnable(boolean[] ioEnable) throws RemoteException { // Get the working status of the receiver&#39;s radio, network, and serial ports } ​ @Override public void getIoData(GnssDataConfigList list) throws RemoteException { // Get the corresponding output DATA of the receiver IO } ​ @Override public void getNmeaOutputList(NmeaData[] nmeaArray) throws RemoteException { // Get the NMEA output list for the specified IO of the receiver } ​ @Override public void getGnssPdopMask(int i) throws RemoteException { // Get the PDOP limit value of the receiver } ​ @Override public void getGnssElevmask(int i) throws RemoteException { // Get the elevation mask angle of the receiver } ​ @Override public void getEbubbleInfo(EbubbleInfo ebubbleInfo) throws RemoteException { // Set the inclination sensor data to output at a fixed frequency } ​ @Override public void getMagnetometerInfo(MagnetometerInfo magnetometerInfo) throws RemoteException { // Set the gyroscope data to output at @Override public void getBasePositionList(BasePositionInfoArray basePositionInfoArray) throws RemoteException { // Get the advanced base station information list of the receiver } ​ @Override public void getBasePositionDifference(float v) throws RemoteException { // Get the translation amount of the advanced base station of the receiver } ​ @Override public void getTransmissionInfo(byte[] bytes) throws RemoteException { // RTCM3 message } ​ /*** Handles CHC_MESSAGE_TYPE_SYSTEM *******************************************************/ ​ @Override public void getReceiverInfo(ReceiverInfo info) throws RemoteException { // Receiver information } ​ @Override public void getRegCode(String regCode) throws RemoteException { // Get the receiver registration code } ​ @Override public void getFileRecordStatus(FileRecordStatus status) throws RemoteException { // File recording status } ​ @Override public void getFileRecordParams(FileRecordInfo info) throws RemoteException { // File recording parameters } ​ @Override public void getFileRecordAutoStart(boolean isAuto) throws RemoteException { // Whether the file is automatically recorded } ​ @Override public void getComBaudrate(Baudrate baudrate) throws RemoteException { // Get the baud rate of the receiver serial port } ​ @Override public void getExpireDate(ExpireDate expireDate) throws RemoteException { // Get the receiver registration expiration date } ​ @Override public void getBattteyLife(int i) throws RemoteException { // Get the receiver battery life: 12 indicates external power, &lt;= 2 indicates low battery, &lt;= 5 indicates 1 bar, &lt;= 9 indicates 2 bars } ​ /*** Handles CHC_MESSAGE_TYPE_PDA *******************************************************/ ​ @Override public void getModemCommunicationMode(ModemCommunicationMode mode) throws RemoteException { // Get the 3G module mode } ​ @Override public void getModemDialStatus(ModemDialStatus status) throws RemoteException { // Get the 3G module dial status } ​ @Override public void getCsdDialStatus(ModemDialStatus status) throws RemoteException { // Get the 3G module dial status (GSM) } ​ @Override public void getCsdInfo(CsdInfo info) throws RemoteException { // Get the 3G module GSM dial parameters } ​ @Override public void getModemAutoDialParams(ModemDialParams params) throws RemoteException { // Get the 3G module dial parameters } ​ @Override public void getModemAutoDial(boolean b) throws RemoteException { // Get whether the 3G module auto dials } ​ @Override public void getModemAutoPowerOn(boolean b) throws RemoteException { // Get whether the 3G module auto powers on } ​ @Override public void getModemPowerStatus(PowerStatus powerStatus) throws RemoteException { // Get the power status of the 3G module } ​ @Override public void getWifiAutoPowerOn(boolean auto) throws RemoteException { // Get whether the receiver&#39;s WIFI module auto powers on } ​ @Override public void getWifiInfo(ReceiverWifiInfo info) throws RemoteException { // Get the parameters of the receiver&#39;s WIFI module } ​ @Override public void getWifiStatus(PowerStatus status) throws RemoteException { // Get the WIFI status } ​ @Override public void getModemSignal(ModemSignal modemSignal) throws RemoteException { // Get the signal strength of the 3G module } ​ @Override public void getModemBandMode(ModemBandMode modemBandMode) throws RemoteException { // Get the frequency band of the 3G module } ​ /*** Handles CHC_MESSAGE_TYPE_DATALINK ******************************************************/ ​ @Override public void getRadioPowerStatus(PowerStatus status) throws RemoteException { // Get the power status of the receiver&#39;s radio module } ​ @Override public void getRadioChannelList(RadioChannelArray channelList) throws RemoteException { // Get the receiver&#39;s radio channel list } ​ @Override public void getRadioInfo(RadioInfo info) throws RemoteException { // Get the receiver&#39;s radio information } ​ @Override public void getGprsStatus(NetworkStatus status) throws RemoteException { // Get the status of the receiver&#39;s GPRS module } ​ @Override public void getGprsInfo(GprsInfo info) throws RemoteException { // Get the information of the receiver&#39;s GPRS module } ​ @Override public void getCorsInfo(CorsInfo info) throws RemoteException { // Get the receiver&#39;s CORS settings information } ​ @Override public void getSourceTable(DataSourceList data) throws RemoteException { // Get the source list } ​ @Override public void getRadioAutoPowerOn(boolean b) throws RemoteException { // Get whether the receiver&#39;s radio module auto powers on } ​ @Override public void getGprsLoginMdl(boolean b) throws RemoteException { // Get whether the receiver&#39;s GPRS module auto logs in } ​ @Override public void UpdateFileRecordParamsError() throws RemoteException { // File parameter setting failed } ​ @Override public void GetCmdUpdateError() throws RemoteException { // Receiver GPRS module information setting failed } ​ @Override public void getDiffDataTip() throws RemoteException { // Callback once for each differential data received } @Override public void getBaseWarning(BaseWarning baseWarning) throws RemoteException { // Get base station offset warnings } }; 发送数据给接收机 (设置接收机) # 您可以通过 ReceiverCmdManager 类来给接收机发送命令，这个类是个单例，直接调用即可， 每个接口的含义见接口注释。
