lNehToSrcBlh(tgt54, src84); // Update UI elements with transformed BLH. // Update UI elements with transformed coordinates and error code mTv84B.setText(String.valueOf(Math.toDegrees(src84[0]))); // Convert radians to degrees for latitude (B) mTv84l.setText(String.valueOf(Math.toDegrees(src84[1]))); // Convert radians to degrees for longitude (L) mTv84H.setText(String.valueOf(src84[2])); // Height (H) mTvAntiErroeCode.setText(String.valueOf(errorcode2)); // Error code for transformation } 至此正反算示例介绍完了，关于坐标转换的更多用法，您可以参考下一节。
